    def __get_cache_file(self, key):
        return os.path.join(self.cache_dir, f'{key}.json')

    def __get_temp_file(self):
        return os.path.join(self.temp_dir, f'temp_{int(time.time())}.json')

    def __get_hash(self, key):
        return hashlib.sha256(key.encode()).hexdigest()

    def get(self, key, default=None):
        cache_file = self.__get_cache_file(key)
        if os.path.exists(cache_file):
            with open(cache_file, 'r') as f:
                return json.load(f)
        return default

    def set(self, key, value, expire=3600):
        temp_file = self.__get_temp_file()
        data = {'value': value, 'expires': time.time() + expire}
        with open(temp_file, 'w') as f:
            json.dump(data, f)
        os.sync()
        hash_key = self.__get_hash(key)
        cache_file = self.__get_cache_file(hash_key)
        shutil.move(temp_file, cache_file)

    def delete(self, key):
        cache_file = self.__get_cache_file(key)
        if os.path.exists(cache_file):
            os.remove(cache_file)

    def close(self):
        shutil.rmtree(self.cache_dir)
        shutil.rmtree(self.temp_dir)
        atexit.register(self.close)

def object_cache(ttl=3600):
    cache = Cache()

    def decorator(func):
        def wrapper(*args, **kwargs):
            key = json.dumps(args + kwargs).encode().hex()
            value = cache.get(key)
            if value is not None:
                return value['value']
            result = func(*args, **kwargs)
            cache.set(key, result, ttl)
            return result
        return wrapper
    return decorator

