from typing import Set, List, Dict, TypeVar, Generic

T = TypeVar('T')

class Deduplicator(Generic[T]):
    def __init__(self):
        self.seen: Set[T] = set()
        self.result: List[T] = []

    def add(self, item: T) -> None:
        """Add an item to the deduplicated list."""
        if item not in self.seen:
            self.result.append(item)
            self.seen.add(item)

    def __iter__(self) -> 'Deduplicator[T]':
        return self

    def __next__(self) -> T:
        if self.result:
            return self.result.pop(0)
        raise StopIteration

def deduplicate(input_list: List[T]) -> List[T]:
    """Deduplicate a list of items while preserving insertion order.

    Args:
        input_list: The list of items to deduplicate.

    Returns:
        A new list with the same items as the input list, but with duplicates removed.
    """
    dedup = Deduplicator[T]()
    for item in input_list:
        dedup.add(item)
    return list(dedup)

# Example usage:
data = [1, 2, 2, 3, 4, 4, 5, 6, 6, 7, 8, 8, 9]

deduped_data = deduplicate(data)
print(deduped_data)  # Output: [1, 2, 3, 4, 5, 6, 7, 8, 9]
