import csv
from typing import List, Dict, TypeVar, Generic

T = TypeVar('T')

class TypedCSVParser(Generic[T]):
    def __init__(self, delimiter: str = ','):
        self.delimiter = delimiter

    def parse_file(self, file_path: str) -> List[Dict[str, T]]:
        """
        Parse a CSV file with a configurable delimiter and return typed rows.

        Args:
            file_path (str): Path to the CSV file to parse.

        Returns:
            List[Dict[str, T]]: A list of dictionaries where each key is a column name and each value is a typed value.
        """
        typed_rows: List[Dict[str, T]] = []
        with open(file_path, 'r') as file:
            reader = csv.DictReader(file, fieldnames=None, delimiter=self.delimiter)
            for row in reader:
                typed_row: Dict[str, T] = {}
                for column_name, value in row.items():
                    try:
                        typed_value = self._parse_value(value)
                    except ValueError:
                        typed_value = value  # If parsing fails, use the original value
                    typed_row[column_name] = typed_value
                typed_rows.append(typed_row)
        return typed_rows

    @staticmethod
    def _parse_value(value: str) -> T:
        """
        Attempt to parse a value as a number or date.

        Args:
            value (str): The value to parse.

        Returns:
            T: The parsed value.
        """
        try:
            # Attempt to parse as an integer
            return int(value)
        except ValueError:
            try:
                # Attempt to parse as a float
                return float(value)
            except ValueError:
                # If parsing fails, assume it's a string or date
                pass

        # Attempt to parse as a date
        import dateutil.parser
        try:
            return dateutil.parser.parse(value)
        except ValueError:
            # If parsing fails, assume it's a string
            return value

# Example usage
